script.text:
      /* <flatten type="Javascript"> */
function init$PhysicalCountQtyUpdate$(f) {f.getItem('so_ct')._idle = 9;}
function active$PhysicalCountQtyUpdate$(f) {
  f.add_onResponseComplete(on$PhysicalCountQtyUpdate$ResponseComplete);
  f._looking = f.getItem('so_ct')._controlBehavior;
  f._looking.add_loading(on$InventoryLookupFilter$Before$Loading);
  var o = f.getItem('ngay_ct1');
  o.focus();
  f.live(o);
}
function close$PhysicalCountQtyUpdate$(f) {
  try {f._looking.remove_loading(on$InventoryLookupFilter$Before$Loading);} catch (ex) {}
  try {f.remove_onResponseComplete(on$PhysicalCountQtyUpdate$ResponseComplete);} catch (ex) {}
}
function on$PhysicalCountQtyUpdate$ResponseComplete(f, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      g._voucherNum = f.getItemValue('so_ct').toUpperCase();
      g._alterTitle = [null, [['%s', g._voucherNum, true]]];
      break;
    default:
      break;
  }
}

function on$InventoryLookupFilter$Before$Loading(sender, e) {
  var f = sender._element.parentForm;
  if ((!f.validFields('ngay_ct1')) || (!f.validFields('ngay_ct2'))) e.type.cancelEvent = true;
  else {
    var g = f.grid, w = g.get_element().parentForm;
    var d1 = f.getItemValue('ngay_ct1'), d2 = f.getItemValue('ngay_ct2');
    a = [
      {Name: 'd1', Type: 'DateTime', Value: d1},
      {Name: 'd2', Type: 'DateTime', Value: d2}
    ];
    sender.set_memvars(a);
  }
}
function on$Filter$Retrieve$QueryComplete(f, id, d, l) {
  var g = f.grid;
  g._denyNew = g._denyEdit = g._denyDelete = l;
  g._voucherID = id;
  g._voucherDate = d;
  if (l == 1) g._denyMessage = f._language == 'v' ? 'Đã khóa số liệu, kiểm tra lại ngày khóa sổ.' : 'Data is locked, you must modify system locked date.';
}
/* </flatten> */
